import { GoogleGenAI, Type } from "@google/genai";
import { FractalParams, AIInsight } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getFractalInsight(params: FractalParams): Promise<AIInsight> {
  const prompt = `
    作为一位世界顶级的数学美学专家和生物学家，请基于以下分形参数提供深刻的洞察：
    分形类型: ${params.type}
    参数详情: 
    - 迭代次数: ${params.maxIterations}
    - 缩放级别: ${params.zoom}
    - 特殊参数: Julia实数(${params.juliaCReal}), 树形角度(${params.treeAngle})

    请以JSON格式回答，包含以下字段：
    - mathConcept: 这个参数设置所反映的核心数学原理。
    - natureAnalogy: 这种视觉形态在自然界中最贴切的类比（如某种植物、云朵或地貌）。
    - philosophy: 这种分形结构带给人类的哲学启示。
    请确保使用中文回答。
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            mathConcept: { type: Type.STRING },
            natureAnalogy: { type: Type.STRING },
            philosophy: { type: Type.STRING },
          },
          required: ["mathConcept", "natureAnalogy", "philosophy"],
        },
      },
    });

    const result = JSON.parse(response.text || "{}");
    return result as AIInsight;
  } catch (error) {
    console.error("AI Insight Error:", error);
    return {
      mathConcept: "自相似性是分形的核心，代表了简单规则产生复杂性的力量。",
      natureAnalogy: "这类似于蕨类植物的生长模式，展现了递归的力量。",
      philosophy: "局部包含整体的信息，一沙一世界，一叶一菩提。",
    };
  }
}

import React, { useRef, useEffect, useCallback } from 'react';
import { FractalType, FractalParams } from '../types';

interface Props {
  params: FractalParams;
}

const FractalCanvas: React.FC<Props> = ({ params }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const drawMandelbrot = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    const imageData = ctx.createImageData(width, height);
    const data = imageData.data;

    for (let x = 0; x < width; x++) {
      for (let y = 0; y < height; y++) {
        let zx = 0;
        let zy = 0;
        const cx = (x - width / 2) * (4 / (width * params.zoom)) + params.offsetX;
        const cy = (y - height / 2) * (4 / (height * params.zoom)) + params.offsetY;

        let i = 0;
        while (zx * zx + zy * zy < 4 && i < params.maxIterations) {
          const tmp = zx * zx - zy * zy + cx;
          zy = 2 * zx * zy + cy;
          zx = tmp;
          i++;
        }

        const idx = (x + y * width) * 4;
        const color = i === params.maxIterations ? 0 : (i / params.maxIterations) * 255;
        data[idx] = color * 0.5; // R
        data[idx + 1] = color * 0.8; // G
        data[idx + 2] = color; // B
        data[idx + 3] = 255; // A
      }
    }
    ctx.putImageData(imageData, 0, 0);
  }, [params]);

  const drawJulia = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    const imageData = ctx.createImageData(width, height);
    const data = imageData.data;

    for (let x = 0; x < width; x++) {
      for (let y = 0; y < height; y++) {
        let zx = (x - width / 2) * (4 / (width * params.zoom)) + params.offsetX;
        let zy = (y - height / 2) * (4 / (height * params.zoom)) + params.offsetY;
        const cx = params.juliaCReal;
        const cy = params.juliaCImg;

        let i = 0;
        while (zx * zx + zy * zy < 4 && i < params.maxIterations) {
          const tmp = zx * zx - zy * zy + cx;
          zy = 2 * zx * zy + cy;
          zx = tmp;
          i++;
        }

        const idx = (x + y * width) * 4;
        const color = i === params.maxIterations ? 0 : (i / params.maxIterations) * 255;
        data[idx] = color;
        data[idx + 1] = color * 0.3;
        data[idx + 2] = color * 0.6;
        data[idx + 3] = 255;
      }
    }
    ctx.putImageData(imageData, 0, 0);
  }, [params]);

  const drawTree = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    ctx.clearRect(0, 0, width, height);
    ctx.strokeStyle = '#4ade80';
    ctx.lineWidth = 2;

    const drawBranch = (x: number, y: number, length: number, angle: number, depth: number) => {
      if (depth === 0) return;

      const x2 = x + length * Math.cos(angle * Math.PI / 180);
      const y2 = y + length * Math.sin(angle * Math.PI / 180);

      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.lineTo(x2, y2);
      ctx.stroke();

      drawBranch(x2, y2, length * params.treeLengthRatio, angle - params.treeAngle, depth - 1);
      drawBranch(x2, y2, length * params.treeLengthRatio, angle + params.treeAngle, depth - 1);
    };

    drawBranch(width / 2, height, 100 * params.zoom, -90, Math.min(params.maxIterations / 10, 12));
  }, [params]);

  const drawBarnsley = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    ctx.clearRect(0, 0, width, height);
    ctx.fillStyle = '#22c55e';
    let x = 0, y = 0;

    for (let i = 0; i < params.maxIterations * 100; i++) {
      let nextX, nextY;
      const r = Math.random();

      if (r < 0.01) {
        nextX = 0;
        nextY = 0.16 * y;
      } else if (r < 0.86) {
        nextX = 0.85 * x + 0.04 * y;
        nextY = -0.04 * x + 0.85 * y + 1.6;
      } else if (r < 0.93) {
        nextX = 0.2 * x - 0.26 * y;
        nextY = 0.23 * x + 0.22 * y + 1.6;
      } else {
        nextX = -0.15 * x + 0.28 * y;
        nextY = 0.26 * x + 0.24 * y + 0.44;
      }

      x = nextX;
      y = nextY;

      const px = x * 60 * params.zoom + width / 2 + params.offsetX * 100;
      const py = height - (y * 60 * params.zoom + params.offsetY * 100);
      ctx.fillRect(px, py, 1, 1);
    }
  }, [params]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const { width, height } = canvas.getBoundingClientRect();
    canvas.width = width;
    canvas.height = height;

    switch (params.type) {
      case FractalType.Mandelbrot:
        drawMandelbrot(ctx, width, height);
        break;
      case FractalType.Julia:
        drawJulia(ctx, width, height);
        break;
      case FractalType.FractalTree:
        drawTree(ctx, width, height);
        break;
      case FractalType.BarnsleyFern:
        drawBarnsley(ctx, width, height);
        break;
    }
  }, [params, drawMandelbrot, drawJulia, drawTree, drawBarnsley]);

  return (
    <canvas 
      ref={canvasRef} 
      className="w-full h-full rounded-2xl shadow-2xl transition-all duration-500 bg-black/40"
    />
  );
};

export default FractalCanvas;

import React, { useState, useEffect, useCallback } from 'react';
import { INITIAL_PARAMS, KNOWLEDGE_BASE } from './constants';
import { FractalType, FractalParams, AIInsight } from './types';
import FractalCanvas from './components/FractalCanvas';
import { getFractalInsight } from './services/geminiService';
import { 
  Settings, 
  BookOpen, 
  Cpu, 
  Play, 
  Pause, 
  Info, 
  RefreshCcw, 
  Maximize2,
  ChevronRight,
  ChevronLeft
} from 'lucide-react';

const App: React.FC = () => {
  const [params, setParams] = useState<FractalParams>(INITIAL_PARAMS);
  const [aiInsight, setAiInsight] = useState<AIInsight | null>(null);
  const [isLoadingInsight, setIsLoadingInsight] = useState(false);
  const [isAutoPlaying, setIsAutoPlaying] = useState(false);
  const [activeTab, setActiveTab] = useState<'lab' | 'knowledge'>('lab');
  const [knowledgeIndex, setKnowledgeIndex] = useState(0);

  // Auto-play animation logic
  useEffect(() => {
    let interval: any;
    if (isAutoPlaying) {
      interval = setInterval(() => {
        setParams(prev => {
          if (prev.type === FractalType.Julia) {
            return {
              ...prev,
              juliaCReal: prev.juliaCReal + Math.sin(Date.now() / 2000) * 0.01,
              juliaCImg: prev.juliaCImg + Math.cos(Date.now() / 3000) * 0.01,
            };
          } else if (prev.type === FractalType.FractalTree) {
            return {
              ...prev,
              treeAngle: prev.treeAngle + Math.sin(Date.now() / 1500) * 0.5,
            };
          }
          return { ...prev, zoom: prev.zoom * 1.002 };
        });
      }, 30);
    }
    return () => clearInterval(interval);
  }, [isAutoPlaying]);

  const handleParamChange = (key: keyof FractalParams, value: any) => {
    setParams(prev => ({ ...prev, [key]: value }));
  };

  const fetchAIInsight = async () => {
    setIsLoadingInsight(true);
    const insight = await getFractalInsight(params);
    setAiInsight(insight);
    setIsLoadingInsight(false);
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row p-4 lg:p-6 gap-6 max-w-[1600px] mx-auto">
      {/* Sidebar - Controls & AI */}
      <aside className="w-full lg:w-96 flex flex-col gap-6 order-2 lg:order-1">

        {/* Navigation Tabs */}
        <div className="flex bg-white/5 rounded-xl p-1 glass">
          <button 
            onClick={() => setActiveTab('lab')}
            className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg transition-all ${activeTab === 'lab' ? 'bg-green-600 text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}
          >
            <Settings size={18} />
            实验室
          </button>
          <button 
            onClick={() => setActiveTab('knowledge')}
            className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg transition-all ${activeTab === 'knowledge' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}
          >
            <BookOpen size={18} />
            知识库
          </button>
        </div>

        {activeTab === 'lab' ? (
          <div className="flex flex-col gap-6">
            {/* Parameters Selection */}
            <div className="glass rounded-2xl p-6 space-y-6">
              <div className="flex items-center gap-2 mb-2">
                <Settings className="text-green-400" size={20} />
                <h2 className="text-xl font-bold">参数调节</h2>
              </div>

              <div className="space-y-4">
                <div>
                  <label className="text-sm text-gray-400 block mb-2">分形类型</label>
                  <select 
                    value={params.type}
                    onChange={(e) => handleParamChange('type', e.target.value)}
                    className="w-full bg-black/40 border border-white/10 rounded-lg p-2 text-sm focus:ring-2 focus:ring-green-500 outline-none"
                  >
                    {Object.values(FractalType).map(type => (
                      <option key={type} value={type}>{type}</option>
                    ))}
                  </select>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-xs text-gray-400 block mb-1">缩放: {params.zoom.toFixed(2)}</label>
                    <input 
                      type="range" min="0.1" max="50" step="0.1" value={params.zoom}
                      onChange={(e) => handleParamChange('zoom', parseFloat(e.target.value))}
                      className="w-full accent-green-500"
                    />
                  </div>
                  <div>
                    <label className="text-xs text-gray-400 block mb-1">迭代: {params.maxIterations}</label>
                    <input 
                      type="range" min="10" max="1000" step="10" value={params.maxIterations}
                      onChange={(e) => handleParamChange('maxIterations', parseInt(e.target.value))}
                      className="w-full accent-blue-500"
                    />
                  </div>
                </div>

                {(params.type === FractalType.Julia) && (
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="text-xs text-gray-400 block mb-1">复数实部 (Re)</label>
                      <input 
                        type="number" step="0.01" value={params.juliaCReal}
                        onChange={(e) => handleParamChange('juliaCReal', parseFloat(e.target.value))}
                        className="w-full bg-black/40 border border-white/10 rounded p-1 text-xs"
                      />
                    </div>
                    <div>
                      <label className="text-xs text-gray-400 block mb-1">复数虚部 (Im)</label>
                      <input 
                        type="number" step="0.01" value={params.juliaCImg}
                        onChange={(e) => handleParamChange('juliaCImg', parseFloat(e.target.value))}
                        className="w-full bg-black/40 border border-white/10 rounded p-1 text-xs"
                      />
                    </div>
                  </div>
                )}

                {(params.type === FractalType.FractalTree) && (
                  <div>
                    <label className="text-xs text-gray-400 block mb-1">分叉角度: {params.treeAngle}°</label>
                    <input 
                      type="range" min="0" max="180" value={params.treeAngle}
                      onChange={(e) => handleParamChange('treeAngle', parseFloat(e.target.value))}
                      className="w-full accent-emerald-500"
                    />
                  </div>
                )}
              </div>

              <div className="flex gap-3">
                <button 
                  onClick={() => setIsAutoPlaying(!isAutoPlaying)}
                  className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl font-medium transition-all ${isAutoPlaying ? 'bg-red-500/20 text-red-400 border border-red-500/50' : 'bg-green-600/20 text-green-400 border border-green-500/50 hover:bg-green-600/30'}`}
                >
                  {isAutoPlaying ? <><Pause size={18} /> 停止演化</> : <><Play size={18} /> 自动演化</>}
                </button>
                <button 
                  onClick={() => setParams(INITIAL_PARAMS)}
                  className="p-3 bg-white/5 hover:bg-white/10 rounded-xl transition-all border border-white/10"
                >
                  <RefreshCcw size={18} />
                </button>
              </div>
            </div>

            {/* AI Insight Module */}
            <div className="glass rounded-2xl p-6 relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                <Cpu size={60} />
              </div>
              <div className="flex items-center gap-2 mb-4">
                <Cpu className="text-blue-400" size={20} />
                <h2 className="text-xl font-bold">AI 智慧洞察</h2>
              </div>

              {!aiInsight && !isLoadingInsight ? (
                <div className="text-center py-6">
                  <p className="text-gray-400 text-sm mb-4">分析当前分形结构的数学奥秘与自然启示</p>
                  <button 
                    onClick={fetchAIInsight}
                    className="px-6 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg text-sm font-medium transition-colors shadow-lg shadow-blue-900/40"
                  >
                    获取分析
                  </button>
                </div>
              ) : isLoadingInsight ? (
                <div className="flex flex-col items-center py-8 gap-4">
                  <div className="w-10 h-10 border-4 border-blue-500/30 border-t-blue-500 rounded-full animate-spin"></div>
                  <p className="text-sm text-blue-400 animate-pulse">正在解码宇宙的数学语言...</p>
                </div>
              ) : (
                <div className="space-y-4 text-sm animate-in fade-in slide-in-from-bottom-2">
                  <div className="bg-white/5 p-3 rounded-lg border border-white/5">
                    <span className="text-blue-400 font-bold block mb-1 uppercase tracking-wider text-[10px]">数学原理</span>
                    <p className="text-gray-300 leading-relaxed">{aiInsight?.mathConcept}</p>
                  </div>
                  <div className="bg-white/5 p-3 rounded-lg border border-white/5">
                    <span className="text-green-400 font-bold block mb-1 uppercase tracking-wider text-[10px]">自然类比</span>
                    <p className="text-gray-300 leading-relaxed">{aiInsight?.natureAnalogy}</p>
                  </div>
                  <div className="bg-white/5 p-3 rounded-lg border border-white/5">
                    <span className="text-purple-400 font-bold block mb-1 uppercase tracking-wider text-[10px]">哲学启示</span>
                    <p className="italic text-gray-400 leading-relaxed">"{aiInsight?.philosophy}"</p>
                  </div>
                  <button 
                    onClick={fetchAIInsight}
                    className="w-full text-xs text-blue-400 hover:text-blue-300 text-center mt-2"
                  >
                    更新洞察
                  </button>
                </div>
              )}
            </div>
          </div>
        ) : (
          /* Knowledge Gallery Section */
          <div className="flex flex-col gap-6 animate-in fade-in slide-in-from-right-4">
            <div className="glass rounded-2xl p-6">
              <div className="flex items-center gap-2 mb-4">
                <BookOpen className="text-yellow-400" size={20} />
                <h2 className="text-xl font-bold">分形百科</h2>
              </div>

              <div className="relative aspect-video rounded-xl overflow-hidden mb-4 border border-white/10">
                <img 
                  src={KNOWLEDGE_BASE[knowledgeIndex].image} 
                  alt={KNOWLEDGE_BASE[knowledgeIndex].title}
                  className="w-full h-full object-cover"
                />
                <div className="absolute top-2 left-2 px-2 py-1 bg-black/60 rounded text-[10px] text-yellow-400 border border-yellow-400/30 font-bold">
                  {KNOWLEDGE_BASE[knowledgeIndex].category}
                </div>
              </div>

              <h3 className="text-lg font-bold text-white mb-2">{KNOWLEDGE_BASE[knowledgeIndex].title}</h3>
              <p className="text-sm text-gray-400 leading-relaxed mb-6">
                {KNOWLEDGE_BASE[knowledgeIndex].description}
              </p>

              <div className="flex items-center justify-between">
                <span className="text-xs text-gray-500">{knowledgeIndex + 1} / {KNOWLEDGE_BASE.length}</span>
                <div className="flex gap-2">
                  <button 
                    onClick={() => setKnowledgeIndex(prev => Math.max(0, prev - 1))}
                    disabled={knowledgeIndex === 0}
                    className="p-2 bg-white/5 hover:bg-white/10 disabled:opacity-30 rounded-lg transition-all"
                  >
                    <ChevronLeft size={18} />
                  </button>
                  <button 
                    onClick={() => setKnowledgeIndex(prev => Math.min(KNOWLEDGE_BASE.length - 1, prev + 1))}
                    disabled={knowledgeIndex === KNOWLEDGE_BASE.length - 1}
                    className="p-2 bg-white/5 hover:bg-white/10 disabled:opacity-30 rounded-lg transition-all"
                  >
                    <ChevronRight size={18} />
                  </button>
                </div>
              </div>
            </div>

            <div className="glass rounded-2xl p-6">
              <h4 className="font-bold text-white mb-3 text-sm flex items-center gap-2">
                <Info size={16} className="text-blue-400" />
                什么是分形？
              </h4>
              <p className="text-xs text-gray-400 leading-relaxed">
                分形（Fractal）通常被定义为“一个粗糙或零碎的几何形状，可以分成数个部分，且每一部分都（至少近似地）是整体缩小后的形状”。这种性质被称为“自相似性”。
              </p>
            </div>
          </div>
        )}
      </aside>

      {/* Main Viewport - Fractal Visualization */}
      <main className="flex-1 min-h-[500px] lg:min-h-0 order-1 lg:order-2 flex flex-col relative">
        <header className="mb-6 z-10">
          <h1 className="text-3xl lg:text-5xl font-black mb-2 text-gradient tracking-tight">
            分形之境 <span className="text-white opacity-20 text-sm align-middle font-normal ml-2">FRACTAL REALM</span>
