import React, { useRef, useEffect, useCallback } from 'react';
import { FractalType, FractalParams } from '../types';

interface Props {
  params: FractalParams;
}

const FractalCanvas: React.FC<Props> = ({ params }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const drawMandelbrot = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    const imageData = ctx.createImageData(width, height);
    const data = imageData.data;

    const zoomFactor = 4 / (Math.min(width, height) * params.zoom);

    for (let x = 0; x < width; x++) {
      for (let y = 0; y < height; y++) {
        let zx = 0;
        let zy = 0;
        const cx = (x - width / 2) * zoomFactor + params.offsetX;
        const cy = (y - height / 2) * zoomFactor + params.offsetY;

        let i = 0;
        while (zx * zx + zy * zy < 4 && i < params.maxIterations) {
          const tmp = zx * zx - zy * zy + cx;
          zy = 2 * zx * zy + cy;
          zx = tmp;
          i++;
        }

        const idx = (x + y * width) * 4;
        if (i === params.maxIterations) {
          data[idx] = 2; data[idx+1] = 5; data[idx+2] = 10; data[idx+3] = 255;
        } else {
          const hue = (i / params.maxIterations) * 360 + 200; // Blue/Cyan hue
          const sat = 80;
          const light = (i / params.maxIterations) * 60 + 10;

          // Fast HSL to RGB approximation
          const c = (1 - Math.abs(2 * light / 100 - 1)) * sat / 100;
          const x_val = c * (1 - Math.abs((hue / 60) % 2 - 1));
          const m = light / 100 - c / 2;
          let r = 0, g = 0, b = 0;
          if (hue < 60) { r = c; g = x_val; }
          else if (hue < 120) { r = x_val; g = c; }
          else if (hue < 180) { g = c; b = x_val; }
          else if (hue < 240) { g = x_val; b = c; }
          else if (hue < 300) { r = x_val; b = c; }
          else { r = c; b = x_val; }

          data[idx] = (r + m) * 255;
          data[idx + 1] = (g + m) * 255;
          data[idx + 2] = (b + m) * 255;
          data[idx + 3] = 255;
        }
      }
    }
    ctx.putImageData(imageData, 0, 0);
  }, [params]);

  const drawJulia = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    const imageData = ctx.createImageData(width, height);
    const data = imageData.data;
    const zoomFactor = 4 / (Math.min(width, height) * params.zoom);

    for (let x = 0; x < width; x++) {
      for (let y = 0; y < height; y++) {
        let zx = (x - width / 2) * zoomFactor + params.offsetX;
        let zy = (y - height / 2) * zoomFactor + params.offsetY;
        const cx = params.juliaCReal;
        const cy = params.juliaCImg;

        let i = 0;
        while (zx * zx + zy * zy < 4 && i < params.maxIterations) {
          const tmp = zx * zx - zy * zy + cx;
          zy = 2 * zx * zy + cy;
          zx = tmp;
          i++;
        }

        const idx = (x + y * width) * 4;
        if (i === params.maxIterations) {
          data[idx] = 0; data[idx+1] = 0; data[idx+2] = 0; data[idx+3] = 255;
        } else {
          const ratio = i / params.maxIterations;
          data[idx] = ratio * 120; // R
          data[idx + 1] = ratio * 200; // G
          data[idx + 2] = 255; // B
          data[idx + 3] = 255;
        }
      }
    }
    ctx.putImageData(imageData, 0, 0);
  }, [params]);

  const drawTree = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    ctx.clearRect(0, 0, width, height);

    const drawBranch = (x: number, y: number, length: number, angle: number, depth: number) => {
      if (depth === 0) return;

      const x2 = x + length * Math.cos(angle * Math.PI / 180);
      const y2 = y + length * Math.sin(angle * Math.PI / 180);

      const opacity = depth / (params.maxIterations / 10);
      ctx.strokeStyle = `rgba(34, 211, 238, ${opacity + 0.1})`;
      ctx.lineWidth = depth * 0.5;
      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.lineTo(x2, y2);
      ctx.stroke();

      drawBranch(x2, y2, length * params.treeLengthRatio, angle - params.treeAngle, depth - 1);
      drawBranch(x2, y2, length * params.treeLengthRatio, angle + params.treeAngle, depth - 1);
    };

    drawBranch(width / 2, height * 0.8, 120 * params.zoom, -90, Math.min(Math.floor(params.maxIterations / 10), 13));
  }, [params]);

  const drawBarnsley = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    ctx.clearRect(0, 0, width, height);
    ctx.fillStyle = 'rgba(74, 222, 128, 0.6)';
    let x = 0, y = 0;

    const iterations = params.maxIterations * 200;
    for (let i = 0; i < iterations; i++) {
      let nextX, nextY;
      const r = Math.random();

      if (r < 0.01) {
        nextX = 0; nextY = 0.16 * y;
      } else if (r < 0.86) {
        nextX = 0.85 * x + 0.04 * y; nextY = -0.04 * x + 0.85 * y + 1.6;
      } else if (r < 0.93) {
        nextX = 0.2 * x - 0.26 * y; nextY = 0.23 * x + 0.22 * y + 1.6;
      } else {
        nextX = -0.15 * x + 0.28 * y; nextY = 0.26 * x + 0.24 * y + 0.44;
      }

      x = nextX; y = nextY;
      const px = x * 80 * params.zoom + width / 2 + params.offsetX * 200;
      const py = height - (y * 80 * params.zoom + 50 + params.offsetY * 200);
      ctx.fillRect(px, py, 1.2, 1.2);
    }
  }, [params]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Use higher resolution for Retina displays
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);

    const { width, height } = rect;

    switch (params.type) {
      case FractalType.Mandelbrot: drawMandelbrot(ctx, width, height); break;
      case FractalType.Julia: drawJulia(ctx, width, height); break;
      case FractalType.FractalTree: drawTree(ctx, width, height); break;
      case FractalType.BarnsleyFern: drawBarnsley(ctx, width, height); break;
    }
  }, [params, drawMandelbrot, drawJulia, drawTree, drawBarnsley]);

  return (
    <canvas 
      ref={canvasRef} 
      className="w-full h-full block transition-opacity duration-1000 grayscale-[0.2] contrast-[1.1]"
    />
  );
};

