import { GoogleGenAI, Type } from "@google/genai";
import { FractalParams, AIInsight } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getFractalInsight(params: FractalParams): Promise<AIInsight> {
  const prompt = `
    作为一位世界顶级的数学美学专家和生物学家，请基于以下分形参数提供深刻的洞察：
    分形类型: ${params.type}
    参数详情: 
    - 迭代次数: ${params.maxIterations}
    - 缩放级别: ${params.zoom}
    - 坐标位置: (${params.offsetX}, ${params.offsetY})

    请以JSON格式回答，包含以下字段：
    - mathConcept: 这个参数设置所反映的核心数学原理。
    - natureAnalogy: 这种视觉形态在自然界中最贴切的类比（如某种植物、云朵或地貌）。
    - philosophy: 这种分形结构带给人类的哲学启示。
    请确保使用中文回答。
  `;

  try {
    const response = await ai.models.generateContent({
      model: params.aiModel,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            mathConcept: { type: Type.STRING },
            natureAnalogy: { type: Type.STRING },
            philosophy: { type: Type.STRING },
          },
          required: ["mathConcept", "natureAnalogy", "philosophy"],
        },
      },
    });

    const result = JSON.parse(response.text || "{}");
    return result as AIInsight;
  } catch (error) {
    console.error("AI Insight Error:", error);
    return {
      mathConcept: "自相似性是分形的核心，代表了简单规则产生复杂性的力量。",
      natureAnalogy: "这类似于蕨类植物的生长模式，展现了递归的力量。",
      philosophy: "局部包含整体的信息，一沙一世界，一叶一菩提。",
    };
  }
}

import React, { useRef, useEffect, useCallback, useState } from 'react';
import { FractalType, FractalParams } from '../types';

interface Props {
  params: FractalParams;
  onPan: (dx: number, dy: number) => void;
}

const FractalCanvas: React.FC<Props> = ({ params, onPan }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [lastMousePos, setLastMousePos] = useState({ x: 0, y: 0 });

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    const dx = e.clientX - lastMousePos.x;
    const dy = e.clientY - lastMousePos.y;

    // Convert pixel movement to coordinate movement
    const canvas = canvasRef.current;
    if (canvas) {
      const zoomFactor = 4 / (Math.min(canvas.width, canvas.height) / (window.devicePixelRatio || 1) * params.zoom);
      onPan(-dx * zoomFactor, dy * zoomFactor);
    }

    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const drawMandelbrot = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    const imageData = ctx.createImageData(width, height);
    const data = imageData.data;
    const zoomFactor = 4 / (Math.min(width, height) * params.zoom);

    for (let x = 0; x < width; x++) {
      for (let y = 0; y < height; y++) {
        let zx = 0;
        let zy = 0;
        const cx = (x - width / 2) * zoomFactor + params.offsetX;
        const cy = (y - height / 2) * zoomFactor + params.offsetY;

        let i = 0;
        while (zx * zx + zy * zy < 4 && i < params.maxIterations) {
          const tmp = zx * zx - zy * zy + cx;
          zy = 2 * zx * zy + cy;
          zx = tmp;
          i++;
        }

        const idx = (x + y * width) * 4;
        if (i === params.maxIterations) {
          data[idx] = 20; data[idx+1] = 40; data[idx+2] = 80; data[idx+3] = 255;
        } else {
          const ratio = i / params.maxIterations;
          data[idx] = 100 + ratio * 155;
          data[idx + 1] = 180 + ratio * 75;
          data[idx + 2] = 255;
          data[idx + 3] = 255;
        }
      }
    }
    ctx.putImageData(imageData, 0, 0);
  }, [params]);

  const drawJulia = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    const imageData = ctx.createImageData(width, height);
    const data = imageData.data;
    const zoomFactor = 4 / (Math.min(width, height) * params.zoom);

    for (let x = 0; x < width; x++) {
      for (let y = 0; y < height; y++) {
        let zx = (x - width / 2) * zoomFactor + params.offsetX;
        let zy = (y - height / 2) * zoomFactor + params.offsetY;
        const cx = params.juliaCReal;
        const cy = params.juliaCImg;

        let i = 0;
        while (zx * zx + zy * zy < 4 && i < params.maxIterations) {
          const tmp = zx * zx - zy * zy + cx;
          zy = 2 * zx * zy + cy;
          zx = tmp;
          i++;
        }

        const idx = (x + y * width) * 4;
        if (i === params.maxIterations) {
          data[idx] = 30; data[idx+1] = 20; data[idx+2] = 60; data[idx+3] = 255;
        } else {
          const ratio = i / params.maxIterations;
          data[idx] = 255 - ratio * 100;
          data[idx + 1] = 200 - ratio * 50;
          data[idx + 2] = 255;
          data[idx + 3] = 255;
        }
      }
    }
    ctx.putImageData(imageData, 0, 0);
  }, [params]);

  const drawTree = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    ctx.clearRect(0, 0, width, height);
    const drawBranch = (x: number, y: number, length: number, angle: number, depth: number) => {
      if (depth === 0) return;
      const x2 = x + length * Math.cos(angle * Math.PI / 180);
      const y2 = y + length * Math.sin(angle * Math.PI / 180);
      ctx.strokeStyle = `rgba(59, 130, 246, ${depth / 10 + 0.2})`;
      ctx.lineWidth = depth * 0.8;
      ctx.beginPath(); ctx.moveTo(x, y); ctx.lineTo(x2, y2); ctx.stroke();
      drawBranch(x2, y2, length * params.treeLengthRatio, angle - params.treeAngle, depth - 1);
      drawBranch(x2, y2, length * params.treeLengthRatio, angle + params.treeAngle, depth - 1);
    };
    drawBranch(width / 2 + params.offsetX * 100, height * 0.9 - params.offsetY * 100, 100 * params.zoom, -90, 10);
  }, [params]);

  const drawBarnsley = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    ctx.clearRect(0, 0, width, height);
    ctx.fillStyle = 'rgba(6, 182, 212, 0.7)';
    let x = 0, y = 0;
    for (let i = 0; i < params.maxIterations * 200; i++) {
      let nextX, nextY;
      const r = Math.random();
      if (r < 0.01) { nextX = 0; nextY = 0.16 * y; }
      else if (r < 0.86) { nextX = 0.85 * x + 0.04 * y; nextY = -0.04 * x + 0.85 * y + 1.6; }
      else if (r < 0.93) { nextX = 0.2 * x - 0.26 * y; nextY = 0.23 * x + 0.22 * y + 1.6; }
      else { nextX = -0.15 * x + 0.28 * y; nextY = 0.26 * x + 0.24 * y + 0.44; }
      x = nextX; y = nextY;
      const px = x * 70 * params.zoom + width / 2 + params.offsetX * 200;
      const py = height - (y * 70 * params.zoom + 50 + params.offsetY * 200);
      ctx.fillRect(px, py, 1.2, 1.2);
    }
  }, [params]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);
    const { width, height } = rect;
    switch (params.type) {
      case FractalType.Mandelbrot: drawMandelbrot(ctx, width, height); break;
      case FractalType.Julia: drawJulia(ctx, width, height); break;
      case FractalType.FractalTree: drawTree(ctx, width, height); break;
      case FractalType.BarnsleyFern: drawBarnsley(ctx, width, height); break;
    }
  }, [params, drawMandelbrot, drawJulia, drawTree, drawBarnsley]);

  return (
    <canvas 
      ref={canvasRef} 
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
      className="w-full h-full block transition-opacity duration-1000 drag-cursor"
    />
  );
};

export default FractalCanvas;

