import React, { useRef, useEffect, useCallback, useState } from 'react';
import { FractalType, FractalParams } from '../types';

interface Props {
  params: FractalParams;
  onPan: (dx: number, dy: number) => void;
  onZoom: (delta: number) => void;
}

const FractalCanvas: React.FC<Props> = ({ params, onPan, onZoom }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [lastMousePos, setLastMousePos] = useState({ x: 0, y: 0 });

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    const dx = e.clientX - lastMousePos.x;
    const dy = e.clientY - lastMousePos.y;

    const canvas = canvasRef.current;
    if (canvas) {
      const zoomFactor = 4 / (Math.min(canvas.width, canvas.height) / (window.devicePixelRatio || 1) * params.zoom);
      onPan(-dx * zoomFactor, dy * zoomFactor);
    }
    setLastMousePos({ x: e.clientX, y: e.clientY });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const handleWheel = (e: React.WheelEvent) => {
    // 阻止默认滚动行为并触发缩放回调
    onZoom(-e.deltaY * 0.001 * params.zoom);
  };

  const drawJulia = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    const imageData = ctx.createImageData(width, height);
    const data = imageData.data;
    const zoomFactor = 4 / (Math.min(width, height) * params.zoom);

    for (let x = 0; x < width; x++) {
      for (let y = 0; y < height; y++) {
        let zx = (x - width / 2) * zoomFactor + params.offsetX;
        let zy = (y - height / 2) * zoomFactor + params.offsetY;
        const cx = params.juliaCReal;
        const cy = params.juliaCImg;

        let i = 0;
        const maxI = params.maxIterations;
        while (zx * zx + zy * zy < 4 && i < maxI) {
          const tmp = zx * zx - zy * zy + cx;
          zy = 2 * zx * zy + cy;
          zx = tmp;
          i++;
        }

        const idx = (x + y * width) * 4;
        if (i === maxI) {
          data[idx] = 40; data[idx+1] = 20; data[idx+2] = 70; data[idx+3] = 255;
        } else {
          const ratio = i / maxI;
          data[idx] = 200 + ratio * 55;
          data[idx + 1] = 150 + ratio * 105;
          data[idx + 2] = 255;
          data[idx + 3] = 255;
        }
      }
    }
    ctx.putImageData(imageData, 0, 0);
  }, [params]);

  const drawTree = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    ctx.clearRect(0, 0, width, height);
    const drawBranch = (x: number, y: number, length: number, angle: number, depth: number) => {
      if (depth === 0) return;
      const x2 = x + length * Math.cos(angle * Math.PI / 180);
      const y2 = y + length * Math.sin(angle * Math.PI / 180);

      ctx.strokeStyle = `rgba(34, 197, 94, ${depth / 10 + 0.4})`;
      ctx.lineWidth = depth * 1.8;
      ctx.lineCap = 'round';
      ctx.beginPath(); ctx.moveTo(x, y); ctx.lineTo(x2, y2); ctx.stroke();

      drawBranch(x2, y2, length * params.treeLengthRatio, angle - params.treeAngle, depth - 1);
      drawBranch(x2, y2, length * params.treeLengthRatio, angle + params.treeAngle, depth - 1);
    };
    drawBranch(width / 2 + params.offsetX * 200, height * 0.9 - params.offsetY * 200, 140 * params.zoom, -90, 10);
  }, [params]);

  const drawKoch = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    ctx.clearRect(0, 0, width, height);
    ctx.strokeStyle = '#3b82f6';
    ctx.lineWidth = 2;
    ctx.lineJoin = 'round';

    const drawLine = (x1: number, y1: number, x2: number, y2: number, depth: number) => {
      if (depth === 0) {
        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);
        ctx.stroke();
        return;
      }

      const dx = (x2 - x1) / 3;
      const dy = (y2 - y1) / 3;
      const p1x = x1 + dx;
      const p1y = y1 + dy;
      const p2x = x1 + 2 * dx;
      const p2y = y1 + 2 * dy;
      const h = Math.sqrt(3) / 2;
      const midx = (x1 + x2) / 2 - h * dy;
      const midy = (y1 + y2) / 2 + h * dx;

      drawLine(x1, y1, p1x, p1y, depth - 1);
      drawLine(p1x, p1y, midx, midy, depth - 1);
      drawLine(midx, midy, p2x, p2y, depth - 1);
      drawLine(p2x, p2y, x2, y2, depth - 1);
    };

    const side = 400 * params.zoom;
    const h = side * (Math.sqrt(3) / 2);
    const x = width / 2 - side / 2 + params.offsetX * 200;
    const y = height / 2 + h / 3 - params.offsetY * 200;
    const depth = Math.min(Math.floor(params.maxIterations / 20), 5);

    drawLine(x, y, x + side, y, depth);
    drawLine(x + side, y, x + side / 2, y - h, depth);
    drawLine(x + side / 2, y - h, x, y, depth);
  }, [params]);

  const drawBarnsley = useCallback((ctx: CanvasRenderingContext2D, width: number, height: number) => {
    ctx.clearRect(0, 0, width, height);
    ctx.fillStyle = 'rgba(6, 182, 212, 0.9)';
    let x = 0, y = 0;
    const iterations = params.maxIterations * 500;
    for (let i = 0; i < iterations; i++) {
      let nextX, nextY;
      const r = Math.random();
      if (r < 0.01) { nextX = 0; nextY = 0.16 * y; }
      else if (r < 0.86) { nextX = 0.85 * x + 0.04 * y; nextY = -0.04 * x + 0.85 * y + 1.6; }
      else if (r < 0.93) { nextX = 0.2 * x - 0.26 * y; nextY = 0.23 * x + 0.22 * y + 1.6; }
      else { nextX = -0.15 * x + 0.28 * y; nextY = 0.26 * x + 0.24 * y + 0.44; }
      x = nextX; y = nextY;
      const px = x * 85 * params.zoom + width / 2 + params.offsetX * 300;
      const py = height - (y * 85 * params.zoom + 80 + params.offsetY * 300);
      ctx.fillRect(px, py, 1.8, 1.8);
    }
  }, [params]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d', { alpha: false });
    if (!ctx) return;
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);
    const { width, height } = rect;

    ctx.fillStyle = 'white';
    ctx.fillRect(0, 0, width, height);

    switch (params.type) {
      case FractalType.Julia: drawJulia(ctx, width, height); break;
      case FractalType.FractalTree: drawTree(ctx, width, height); break;
      case FractalType.BarnsleyFern: drawBarnsley(ctx, width, height); break;
      case FractalType.KochSnowflake: drawKoch(ctx, width, height); break;
    }
  }, [params, drawJulia, drawTree, drawBarnsley, drawKoch]);

  return (
    <canvas 
      ref={canvasRef} 
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
      onWheel={handleWheel}
      className="w-full h-full block drag-cursor"
    />
  );
};

export default FractalCanvas;

